SELECT traders.trader_name, alerts.ticker, alerts.alert_condition, alerts.alert_value
FROM traders
JOIN alerts ON traders.trader_id = alerts.trader_id;

SELECT trader_id, trader_name
FROM traders
WHERE role = 'trader';

SELECT traders.trader_name, watchlists.watchlist_name
FROM traders
INNER JOIN watchlists ON traders.trader_id = watchlists.trader_id;

SELECT t.trader_name
FROM traders t
JOIN user_permissions up ON t.trader_id = up.role_id
WHERE up.permission = 'buy' AND t.trader_id NOT IN (
  SELECT trader_id FROM transactions
);
